promptTemplate:
당신은 B2B SaaS 데이터 분석 전문가입니다.
다음 입력 정보를 기반으로 오디언스 전략 리포트 데이터를 생성해주세요.

입력: {input}

아래 ReportSchema JSON 구조를 정확히 따르는 JSON만 반환하세요. 설명 없이 JSON만:
{
  "meta": { "agentId": "audience-strategy", "agentName": "오디언스 전략", "createdAt": "ISO날짜" },
  "executiveSummary": {
    "keyFindings": ["핵심 발견 3-5개"],
    "distributions": [{ "label": "세그먼트 분포", "data": {} }]
  },
  "tabs": [
    {
      "id": "analysis-report",
      "label": "분석 리포트",
      "sections": [
        { "id": "kpi-overview", "label": "KPI 개요", "componentType": "MetricCard", "data": { "items": [{"label": string, "value": string|number, "unit": string}] } },
        { "id": "segment-score", "label": "세그먼트 점수", "componentType": "ScoreCard", "data": { "score": number, "maxScore": 100, "badge": string, "bullets": [string] } },
        { "id": "do-dont", "label": "DO / DON'T", "componentType": "DoDontCard", "data": { "dos": [string], "donts": [string] } },
        { "id": "sample-customers", "label": "샘플 고객", "componentType": "SampleCard", "data": { "items": [{"id": string, "bullets": [string]}] } }
      ]
    },
    {
      "id": "population-expansion",
      "label": "오디언스 확장",
      "sections": [
        { "id": "expansion-segments", "label": "확장 세그먼트", "componentType": "BulletCard", "data": { "title": string, "bullets": [string] } },
        { "id": "segment-metrics", "label": "세그먼트 KPI", "componentType": "MetricCard", "data": { "items": [{"label": string, "value": string|number, "unit": string}] } },
        { "id": "strategy-table", "label": "실행 계획", "componentType": "StrategyTable", "data": { "immediate": [], "short": [], "mid": [] } },
        { "id": "revenue-scenario", "label": "수익 시나리오", "componentType": "RevenueScenarioBar", "data": { "unit": "억원", "scenarios": [{"label": "Upside", "value": number}, {"label": "Base", "value": number}, {"label": "Downside", "value": number}] } }
      ]
    }
  ]
}
